+                .ob_refcnt = 1,
+                .ob_type = &cpython.PyTuple_Type,
+            },
+            .ob_size = @intCast(count),
+        },
+        .ob_item = @ptrCast(@alignCast(mem.ptr + @sizeOf(cpython.PyTupleObject))),
+    };
