+            }
+        }
+        // Otherwise return uncertain
+        return ZigValue.pyvalue(.unknown);
+    }
+
+    // ============================================
+    // Utility Functions
+    // ============================================
+
+    /// Convert Python comparison operator to CompOp
+    pub fn cmpOpToCompOp(op: ast.CmpOp) CompOp {
+        return switch (op) {
+            .Eq => .eq,
+            .NotEq => .ne,
+            .Lt => .lt,
+            .LtE => .le,
+            .Gt => .gt,
+            .GtE => .ge,
+            .In => .in_,
+            .NotIn => .not_in,
+            .Is => .is,
+            .IsNot => .is_not,
+        };
+    }
